<script>
(function() {
  const WEEKDAYS = ['Sunday','Monday','Tuesday','Wednesday','Thursday','Friday','Saturday'];
  const MONTHS = ['January','February','March','April','May','June','July','August','September','October','November','December'];
  const MONTHS_SHORT = ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep','Oct','Nov','Dec'];
  const MOOD_EMOJI = { '1': '😵', '2': '😐', '3': '😊', '4': '🔥' };

  let data = {};
  let currentYear, currentMonth;

  async function loadData() {
    try {
      const base = document.querySelector('meta[name="quarto:offset"]');
      const offset = base ? base.getAttribute('content') : '.';
      const res = await fetch(offset + '/_data/til.json');
      if (res.ok) data = await res.json();
    } catch (e) { console.warn('Could not load TIL data:', e); }
    renderCalendar();
  }

  function escHtml(s) { return s.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
  function mondayIndex(jsDay) { return (jsDay + 6) % 7; }

  function renderCalendar() {
    const grid = document.getElementById('til-cal-grid');
    grid.innerHTML = '';
    const today = new Date();
    const firstDay = new Date(currentYear, currentMonth, 1).getDay();
    const daysInMonth = new Date(currentYear, currentMonth + 1, 0).getDate();
    const emptySlots = mondayIndex(firstDay);

    document.getElementById('til-month-label').innerHTML = MONTHS[currentMonth] + ' <span>' + currentYear + '</span>';

    for (let i = 0; i < emptySlots; i++) { const el = document.createElement('div'); el.className = 'til-cell empty'; grid.appendChild(el); }

    for (let d = 1; d <= daysInMonth; d++) {
      const key = currentYear + '-' + String(currentMonth+1).padStart(2,'0') + '-' + String(d).padStart(2,'0');
      const entry = data[key];
      const isToday = today.getFullYear() === currentYear && today.getMonth() === currentMonth && today.getDate() === d;
      const cell = document.createElement('div');
      cell.className = 'til-cell' + (isToday ? ' today' : '') + (entry && entry.text ? ' has-entry' : '');
      if (entry && entry.text && entry.text.length > 80) cell.classList.add('rich');
      cell.innerHTML = '<div class="til-cell-num">' + d + '<div class="til-cell-dot"></div></div><div class="til-cell-preview">' + (entry ? escHtml(entry.text || '') : '') + '</div>';
      if (entry && entry.text) cell.addEventListener('click', () => openModal(key));
      grid.appendChild(cell);
    }
    updateStats(); renderSidebar(); renderHeatmap();
  }

  function updateStats() {
    const allKeys = Object.keys(data).filter(k => data[k] && data[k].text);
    const today = new Date();
    const monthKeys = allKeys.filter(k => { const d = new Date(k); return d.getFullYear() === today.getFullYear() && d.getMonth() === today.getMonth(); });
    const streak = calcStreak();
    document.getElementById('til-stat-total').textContent = allKeys.length;
    document.getElementById('til-stat-month').textContent = monthKeys.length;
    document.getElementById('til-stat-streak').textContent = streak;
    document.getElementById('til-streak-display').textContent = '🔥 ' + streak + ' day streak';
  }

  function calcStreak() {
    let streak = 0, d = new Date();
    while (true) {
      const k = d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
      if (data[k] && data[k].text) { streak++; d.setDate(d.getDate()-1); } else break;
    }
    return streak;
  }

  function renderSidebar() {
    const list = document.getElementById('til-sidebar-list');
    const entries = Object.keys(data).filter(k => data[k] && data[k].text).sort((a,b) => b.localeCompare(a)).slice(0, 20);
    if (!entries.length) { list.innerHTML = '<div class="til-sidebar-empty">No entries yet.</div>'; return; }
    list.innerHTML = entries.map(k => {
      const e = data[k], d = new Date(k + 'T00:00:00');
      const label = MONTHS_SHORT[d.getMonth()] + ' ' + d.getDate() + ', ' + d.getFullYear();
      const tags = (e.tags || []).map(t => '<span class="til-list-tag">' + t + '</span>').join('');
      return '<div class="til-list-item" data-key="' + k + '"><div class="til-list-date">' + label + '</div><div class="til-list-text">' + escHtml(e.text) + '</div>' + (tags ? '<div class="til-list-tags">' + tags + '</div>' : '') + '</div>';
    }).join('');
    list.querySelectorAll('.til-list-item').forEach(el => { el.addEventListener('click', () => openModal(el.dataset.key)); });
  }

  function renderHeatmap() {
    const grid = document.getElementById('til-heatmap-grid'), monthsRow = document.getElementById('til-heatmap-months');
    grid.innerHTML = ''; monthsRow.innerHTML = '';
    const today = new Date(), year = today.getFullYear();
    const jan1 = new Date(year, 0, 1), startOffset = mondayIndex(jan1.getDay());
    const start = new Date(jan1); start.setDate(start.getDate() - startOffset);
    MONTHS_SHORT.forEach(m => { const s = document.createElement('span'); s.className = 'til-heatmap-month-label'; s.textContent = m; monthsRow.appendChild(s); });
    const dec31 = new Date(year, 11, 31); let cur = new Date(start);
    while (cur <= dec31) {
      const k = cur.getFullYear() + '-' + String(cur.getMonth()+1).padStart(2,'0') + '-' + String(cur.getDate()).padStart(2,'0');
      const cell = document.createElement('div'); cell.className = 'til-heat-cell';
      if (cur > today || cur.getFullYear() < year) cell.classList.add('future');
      else if (data[k] && data[k].text) { const len = data[k].text.length; cell.classList.add(len > 150 ? 'active-3' : len > 60 ? 'active-2' : 'active'); }
      cell.title = k; grid.appendChild(cell); cur.setDate(cur.getDate() + 1);
    }
  }

  function openModal(key) {
    const entry = data[key]; if (!entry || !entry.text) return;
    const p = key.split('-'), dateObj = new Date(+p[0], +p[1]-1, +p[2]);
    document.getElementById('til-modal-date').textContent = MONTHS[dateObj.getMonth()] + ' ' + dateObj.getDate() + ', ' + p[0];
    document.getElementById('til-modal-weekday').textContent = WEEKDAYS[dateObj.getDay()];
    document.getElementById('til-modal-text').textContent = entry.text;
    document.getElementById('til-modal-tags').innerHTML = (entry.tags || []).map(t => '<span class="til-modal-tag">' + t + '</span>').join('');
    document.getElementById('til-modal-mood').textContent = entry.mood ? (MOOD_EMOJI[entry.mood] || '') : '';
    document.getElementById('til-modal-backdrop').classList.add('open');
  }

  function closeModal() { document.getElementById('til-modal-backdrop').classList.remove('open'); }
  document.getElementById('til-modal-close').onclick = closeModal;
  document.getElementById('til-modal-backdrop').onclick = (e) => { if (e.target === document.getElementById('til-modal-backdrop')) closeModal(); };
  document.getElementById('til-prev').onclick = () => { currentMonth--; if (currentMonth < 0) { currentMonth = 11; currentYear--; } renderCalendar(); };
  document.getElementById('til-next').onclick = () => { currentMonth++; if (currentMonth > 11) { currentMonth = 0; currentYear++; } renderCalendar(); };
  document.getElementById('til-today-btn').onclick = () => { const n = new Date(); currentYear = n.getFullYear(); currentMonth = n.getMonth(); renderCalendar(); };
  document.addEventListener('keydown', (e) => { if (e.key === 'Escape') closeModal(); });

  const now = new Date(); currentYear = now.getFullYear(); currentMonth = now.getMonth(); loadData();
})();
</script>
